import microcoapy
import network
import time
import gc

# --- Device State ---
current_temperature = 25.5
light_state = False # False for off, True for on

# --- CoAP Server Setup ---
COAP_SERVER_PORT = 5683

def setup_wifi(ssid, password):
    """Connects to Wi-Fi network."""
    print("Connecting to WiFi...")
    sta_if = network.WLAN(network.STA_IF)
    sta_if.active(True)
    sta_if.connect(ssid, password)
    while not sta_if.isconnected():
        time.sleep(1)
        print(".", end="")
    print("\nWiFi connected!")
    print("IP address:", sta_if.ifconfig()[0])
    return sta_if

# --- Resource Handlers ---

def get_temperature_handler(request):
    """Handles GET requests for /sensors/temp."""
    print(f"GET /sensors/temp from {request.remote_addr}")
    
    # Simulate a slight temperature change for demonstration
    global current_temperature
    current_temperature += 0.1
    if current_temperature > 30.0:
        current_temperature = 25.0
    
    payload = f"{current_temperature:.1f}"
    
    return microcoapy.CoapResponse(
        code=microcoapy.COAP_RESPONSE_CODE.COAP_RESPONSE_CODE_CONTENT, # 2.05 Content
        payload=payload,
        content_format=microcoapy.COAP_CONTENT_FORMAT.COAP_CONTENT_FORMAT_TEXT_PLAIN
    )

def get_light_handler(request):
    """Handles GET requests for /actuators/light."""
    print(f"GET /actuators/light from {request.remote_addr}")
    
    payload = "on" if light_state else "off"
    
    return microcoapy.CoapResponse(
        code=microcoapy.COAP_RESPONSE_CODE.COAP_RESPONSE_CODE_CONTENT, # 2.05 Content
        payload=payload,
        content_format=microcoapy.COAP_CONTENT_FORMAT.COAP_CONTENT_FORMAT_TEXT_PLAIN
    )

def put_light_handler(request):
    """Handles PUT requests for /actuators/light."""
    print(f"PUT /actuators/light from {request.remote_addr} with payload: {request.payload}")
    global light_state
    
    if request.payload is None:
        return microcoapy.CoapResponse(
            code=microcoapy.COAP_RESPONSE_CODE.COAP_RESPONSE_CODE_BAD_REQUEST, # 4.00 Bad Request
            payload="Payload required (on/off or 1/0)",
            content_format=microcoapy.COAP_CONTENT_FORMAT.COAP_CONTENT_FORMAT_TEXT_PLAIN
        )

    # Decode payload and normalize for comparison
    payload_str = request.payload.decode('utf-8').strip().lower()

    if payload_str == "on" or payload_str == "1":
        light_state = True
        response_payload = "Light turned ON"
        response_code = microcoapy.COAP_RESPONSE_CODE.COAP_RESPONSE_CODE_CHANGED # 2.04 Changed
    elif payload_str == "off" or payload_str == "0":
        light_state = False
        response_payload = "Light turned OFF"
        response_code = microcoapy.COAP_RESPONSE_CODE.COAP_RESPONSE_CODE_CHANGED # 2.04 Changed
    else:
        response_payload = "Invalid light state. Use 'on'/'off' or '1'/'0'."
        response_code = microcoapy.COAP_RESPONSE_CODE.COAP_RESPONSE_CODE_BAD_REQUEST # 4.00 Bad Request

    return microcoapy.CoapResponse(
        code=response_code,
        payload=response_payload,
        content_format=microcoapy.COAP_CONTENT_FORMAT.COAP_CONTENT_FORMAT_TEXT_PLAIN
    )

# --- Main Server Logic ---
def run_coap_server():
    """Initializes and runs the CoAP server."""
    print("Initializing CoAP server...")
    coap_server = microcoapy.Coap()

    # Add resources
    # /sensors/temp - GET only
    coap_server.add_resource(
        path="sensors/temp",
        callback=get_temperature_handler,
        methods=[microcoapy.COAP_METHOD.GET]
    )

    # /actuators/light - GET and PUT
    coap_server.add_resource(
        path="actuators/light",
        callback=get_light_handler,
        methods=[microcoapy.COAP_METHOD.GET]
    )
    coap_server.add_resource(
        path="actuators/light",
        callback=put_light_handler,
        methods=[microcoapy.COAP_METHOD.PUT]
    )

    print(f"Starting CoAP server on port {COAP_SERVER_PORT}...")
    coap_server.start(port=COAP_SERVER_PORT)

    print("CoAP server started. Listening for requests...")
    try:
        while True:
            # Process CoAP packets for 100ms
            coap_server.loop(100) 
            time.sleep(0.1) # Small delay to yield CPU
            gc.collect() # Explicitly run garbage collection to manage memory
    except KeyboardInterrupt:
        print("CoAP server stopped by user.")
    finally:
        coap_server.stop()
        print("CoAP server resources released.")

